INSERT INTO chapters (id, story_id, chapter_number, title, content, word_count, view_count, is_published, password, password_question, password_hint, created_at, updated_at, scheduled_at) VALUES ('41fbf336-22a9-4653-aba2-c3d42f397bca', 'NOV03', 1, 'Chương 1: Thiên đạo dị động', 'Từ thuở hồng hoang khai thiên lập địa, chúng sinh trong thiên hạ đã được phân làm hai ngả: một là phàm nhân tục tử, số phận gắn liền với sinh lão bệnh tử, chìm nổi theo dòng luân hồi; một là kẻ tu hành đạp mây cưỡi gió, truy cầu trường sinh bất diệt. Phàm là kẻ có căn cơ thâm hậu, hội đủ thiên thời địa lợi, lập nhiều công trạng, lại thêm một niệm chấp niệm đủ sâu mới có thể chạm tới thiên cơ, dẫn động lôi kiếp, một bước đăng thần.

Đã năm trăm năm trôi qua kể từ lần cuối có người phi thăng, chẳng ai rõ vì sao thiên hạ bặt vô âm tín, chẳng có thêm một nhân tài nào đắc đạo. Mãi cho đến ba trăm năm sau, một vị hoàng đế trẻ tuổi với khát vọng mãnh liệt đã khiến cõi hồng hoang chấn động, phá tan xiềng xích vô hình trói buộc thiên đạo bấy lâu, độ kiếp phi thăng.

Từ ấy, thiên đạo khai mở không còn ràng buộc. Kẻ có duyên với đạo nối nhau bước lên con đường phi thăng. Trong suốt một trăm năm mươi năm tiếp theo, người đắc đạo nhiều như cá vượt vũ môn, thi nhau đăng thần.

Nhưng thịnh cực tất suy.

Dòng người tu hành tuy đông nhưng chẳng còn ai được thiên đạo ưu ái. Tứ phương thiên địa lại rơi vào tĩnh mịch, không còn ai có thể vượt qua lôi kiếp. Đã năm mươi năm trôi qua, thiên hạ không xuất hiện thêm một kẻ phi thăng nào.

Có lời đồn rằng, sau thời kỳ đại thịnh, thiên đạo tuy mở nhưng lại âm thầm biến đổi. Lôi kiếp ngày càng hung hiểm, thiên uy khó lường, kẻ tu hành dù có căn cơ cũng khó lòng chống đỡ.

Cũng có người nói, sau khi vị hoàng đế kia đăng thần, thiên cơ đã bị tiêu hao quá nửa, khiến con đường phi thăng dần khép lại.

Lại có kẻ suy đoán, nơi thượng giới đã xảy ra biến cố, khiến thiên môn tuy còn mà đạo lộ đã đoạn.

Những lời đồn ấy lan truyền khắp thiên hạ, nhưng không ai có thể kiểm chứng. Chỉ biết rằng, năm tháng trôi qua, linh khí vẫn lưu chuyển, đại đạo vẫn tồn tại, nhưng cánh cửa phi thăng… tựa như đã lần nữa khép kín.
Cho đến hôm nay—

Thần Quang điện sừng sững giữa tầng mây, vân hải cuộn trào dưới chân, linh khí hội tụ thành quang mang rực rỡ, tựa như tiên cảnh.

Nhưng hôm nay, trong vẻ tĩnh mịch vốn có lại ẩn chứa một tia dị động.

Đại môn Thần Quang điện xưa nay uy nghiêm mà trầm tĩnh, chưa từng biến đổi, vậy mà lúc này trước cổng lại hiện ra một tấm kim bảng khổng lồ, linh khí lưu chuyển, phù văn ẩn hiện, phá vỡ sự tĩnh lặng kéo dài suốt bao năm.

Kim bảng này ngay lập tức được truyền tới Thức Hải Đồ* của từng vị thần quan, trên dưới thiên đình lập tức dậy sóng. Các điện các phủ đồng loạt mở cửa, văn quan, võ quan, nối nhau ngự vân mà đến. Văn võ quan từng người tranh thủ chỉnh trang lại y phục, chỉnh lại pháp khí bên người, nối đuôi nhau hướng đến Thần Quang điện.

Thức Hải Đồ: giống như hệ thống của mấy bộ truyện xuyên không ý.

Ai nấy đều muốn tận mắt chứng kiến, rốt cuộc là thần thánh phương nào có tu vi thâm hậu đến mức có thể gây chấn động thiên không phi thăng thành thần.

Phải biết rằng, suốt năm mươi năm qua, cả thượng thiên đình chưa từng nghênh đón thêm một vị tân thần quan nào phi thăng. Nay cách bán kỳ niên tịch lặng, lại có người phá giới mà lên, bậc nhân tài hiếm có như vậy, thử hỏi trong thiên đình có ai không nảy sinh lòng hiếu kỳ?

*bán kỳ niên: nửa thế kỉ

Trước cổng đại điện, tiếng người xì xào bàn tán ngày một nhiều. Văn quan tụ thành từng nhóm thấp giọng nghị luận, võ tướng đứng thành hàng mà vẫn không giấu nổi vẻ xôn xao trong mắt, mọi tầm mắt đều tập trung tại kim bảng lớn hơn cái cổng trước Thần Quang điện.

Có kẻ phỏng đoán rằng người ấy hẳn là một chiến tướng lẫy lừng bậc nhất nhân gian, từng quét sạch nghìn quân trong chớp mắt, cùng với tu vi thông thiên, chiến ý ngút trời, bởi vậy mới được thiên đạo để mắt, giáng lôi kiếp mà thu nạp vào hàng thần vị.

Lại có người cho rằng, đó ắt là bậc hiền sĩ tài học uyên thâm, một lời có thể an dân, một kế có thể định quốc, lấy văn đức cảm hóa thiên hạ, nên mới được thiên đạo nhìn trúng, ban cho cơ duyên phi thăng.

Hàng ngàn phiên bản, hàng vạn lời đồn cứ thế lan truyền, người nào người nấy góp một câu, khiến câu chuyện càng lúc càng ly kỳ. Nào ai biết được chân tướng thế nào, chỉ biết đứng ngoài cổng mà phỏng đoán, mặt mày hân hoan như thể sắp được diện kiến thượng tiên giáng trần.

Giữa lúc quần thần còn đang rôm rả nghị luận, tiếng nói cười chưa kịp lắng xuống, thì bỗng “ầm” một tiếng vang dội, cửa lớn đại điện từ từ mở ra. Hai cánh cửa ngọc cao vút chậm rãi tách sang hai bên, linh quang trong điện theo đó ùa ra ngoài như ong vỡ tổ, không quá chói mắt, chỉ đủ khiến vân khí quanh điện khẽ xao động.

Tiếng bàn tán dần dần thưa lại.

Văn quan gấp quạt, võ tướng chỉnh lại đai lưng, từng ánh mắt lần lượt hướng về phía đại điện. Sự náo nhiệt khi nãy vẫn còn đó, chỉ là đã thu liễm lại đôi phần, nhường chỗ cho niềm chờ đợi không giấu được.

Trong khoảng lặng ngắn ngủi ấy, linh lực lưu chuyển êm đềm như dòng nước, mọi sự chú ý đều dồn về phía cánh cửa vừa mở, chính là nơi sắp sửa nghênh đón vị tân thần quan sau ngũ thập niên tĩnh lặng.

Hai cánh cửa ngọc mở rộng, linh quang trong điện nhẹ nhàng lan ra, không chói lóa mà chỉ như một làn sương mỏng phủ lên lớp nền đại điện. Ngay lúc này, quan văn quan võ thi nhau lũ lượt tiến vào.

Trong đại điện, hương trầm thanh nhã phảng phất, mây lành lững lờ quanh các cột trụ chạm vân. Ánh sáng dịu dàng rọi xuống bậc thềm cửu cấp, khiến không gian thêm phần trang nghiêm nhưng không hề nặng nề.

Mọi người nhanh chóng hướng mắt lên vị trí trên cao của đại điện vội tìm kiếm bóng hình quyền lực thường ngày, nhưng tiếc thay, chiếc ghế ấy lại trống không.

“Đế quân sao chưa đến nhỉ? Chẳng phải mấy dịp này ngài ấy rất hứng thú sao?” Một võ thần khẽ hỏi.

“Ngươi quên rồi sao? Ngài ấy đi sứ phương bắc rồi, khoảng chừng một tháng mới trở về.” Một văn thần đáp.

Lúc này cả đại điện mới “Ồ!” một tiếng kinh ngạc.

“Vậy… ai sẽ chủ trì hôm nay đây?”

Theo lệ thiên đình, mỗi khi có thần quan phi thăng, Đế quân sẽ dựa vào công lao người ấy khi còn ở nhân gian để định chức. Nếu người đó từng lấy văn trị quốc, an dân bằng trí lược, sẽ được xếp vào hàng văn thần. Nếu lập nhiều chiến công, trấn áp yêu ma, sẽ được quy vào võ bộ. Sau khi định chức xong, Đế quân sẽ giao cho Thiên Văn Giám Chính cử một vị văn thần đến hướng dẫn tân thần quan, giảng giải các quy luật của thiên đình để người mới sớm quen với phép tắc thiên đình.

“Các ngươi quên hắn ta rồi à?”

Lời vừa dứt, đại điện vốn còn rì rầm trong phút chốc lại im bặt. Mấy ánh mắt vừa rồi còn thấp giọng đoán già đoán non nay đồng loạt cụp xuống, thần sắc thoáng hiện vài phần dè chừng cùng ái ngại.

Chuyện này, ai mà không rõ.

Mỗi khi Đế quân vắng mặt, người thay mặt xử lý việc phân định tân thần quan, kiêm luôn việc cai quản thiên đình, chính là Thiêm Văn Giám Chính, người đứng đầu văn ban có nhiệm vụ chưởng quản quy củ cùng điển chương thiên đình.

Mà vị ấy…

Nói dễ nghe là công minh chính trực, quy củ nghiêm khắc, liêm khiết ngời ngời, nói thẳng ra… như quỷ vương đầu thai nhầm chỗ!

Vì vậy, chỉ cần nhắc đến danh hiệu ấy, bầu không khí trong điện tự khắc thu lại vài phần náo nhiệt.

Người giữ chức vụ này, có một cái tên rất dễ nghe nhưng tính cách lại trái ngược.

Trong lúc bầu không khí ồn ào bỗng nhiên dịu xuống, từ ngoài cổng lớn có hai nam tử đang tiến vào.

Nhìn thoáng qua, nếu phải dùng cách nói của nhân gian thì phải nói là…

Mục sắc như họa, thiên tư bất phàm.

Hai người vừa bước vào đại điện, dung mạo thoạt nhìn có đến bảy phần tương đồng.

Người đi trước thân hình cao ráo, dáng bước trầm ổn. Trường bào huyền sắc khẽ lay theo từng nhịp chân, khí độ ung dung mà tự nhiên toát ra uy thế của bậc quân vương. Đôi mắt tím sâu thẳm, lạnh nhạt như mặt hồ mùa đông, nhìn qua liền khiến người khác vô thức thu liễm vài phần tùy tiện.

Người còn lại theo sau nửa bước, nhìn qua có vẻ trẻ hơn đôi phần. Tuy dung mạo mang nét tương đồng, nhưng khí chất lại không hề non nớt. Thần sắc y điềm tĩnh, đôi mắt tím sáng mà trầm, từng bước chân vững vàng, không nhanh không chậm. Dẫu giữ lễ đứng sau, tư thái vẫn thẳng thắn đoan chính, toát lên phong độ của một người đã quen gánh vác trọng trách. Mái tóc buộc cao gọn ghẽ, để lộ gương mặt tuấn tú mà cương nghị, nơi khóe mi thấp thoáng vẻ sắc sảo kín đáo, không phô trương, song cũng đủ khiến người khác phải nhìn thêm lần nữa.

Một người trầm ổn như núi, một người sáng sủa như kiếm mới rút khỏi vỏ đứng cạnh nhau, lại càng khiến người trong điện khó lòng rời mắt.

“Hai người… chẳng lẽ là…” Một vị thần quan lên tiếng phá vỡ bầu không khí.

“Có tận hai người phi thăng cùng lúc sao? Chuyện này quả là kỳ tích.”

“Xin hỏi…” Nam tử buộc tóc cao đằng sau cất tiếng hỏi.

Bỗng chốc cả đám người lao đến.

“Các ngươi là phụ tử sao? Trông giống nhau thế?”

“Khí chất oai phong thế này, dưới trần gian các ngươi là võ tướng phải không?”

“Hai công tử tuấn tú thật đó, võ thần mới à?”

Một đám người có cả văn võ thần quan tụ tập bao vây hai nam tử ở giữa, nhất thời khiến bọn họ không biết nên làm sao cho phải.

“Này…” Một vị võ quan lên tiếng, cố gắng giải tán đám đông.

“Mới đầu ngày ra mà các ngươi nháo nhào cái gì thế hả? Chỗ này để các ngươi làm loạn à?”

Một câu nói đanh thép uy nghiêm cắt ngang lời võ quan và khiến bầu không khí ồn ào trong đại điện lập tức im bặt khiến ai nấy đều sửng sốt.

Lời vừa dứt, mọi ánh nhìn trong đại điện đều dồn cả về phía người vừa lên tiếng.

Khi thấy rõ người đến là ai, cả đám lập tức toát mồ hôi lạnh, mọi lời “thăm hỏi” đều nghẹn lại nơi cổ họng.

“Bái… Bái kiến Thiên Văn đại nhân.” Một vị văn quan lên tiếng, phá vỡ không khí ngượng ngùng này.

“Thật là... chẳng qua chỉ là có thần quan phi thăng, tưởng gì to tát lắm. Các ngươi cứ ồn ào như vậy, kẻ không biết còn tưởng thiên đạo sụp đổ hay sao ấy. Mới có năm mươi năm không ai phi thăng thôi mà, có cần làm quá lên thế không?” 

Một giọng phàn nàn đanh thép vang lên giữa thần điện rộng lớn, khiến ai cũng chảy mồ hôi hột, sợ rằng vị đại nhân này sẽ bắt họ làm khổ sai dưới nhân gian thêm 100 năm nữa.

Lời vừa dứt, bên cạnh Thiên Văn Giám Chính xuất hiện Thức Hải Đồ, trên đó viết rằng:

“Hạ Thiên Nguyệt, tự Nguyên Sương.
Thần vị: Thiên Văn Giám Chính.
Thân phận trước phi thăng: Thập hoàng tử Đại Thục.”', 2167, 0, true, NULL, NULL, NULL, '2026-06-17T05:27:27.791Z', '2026-06-17T05:27:27.791Z', NULL) ON CONFLICT (id) DO NOTHING;

